/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * TRUE sliding window (not fixed window):
 * - Maintains a list of exact request timestamps per IP.
 * - On every request, prunes timestamps older than `windowMs` from *now*.
 * - Counts only the timestamps still inside the moving window.
 * - Rejects only when the live count >= maxRequests.
 *
 * This guarantees that a client never exceeds `maxRequests` in any
 * rolling `windowMs` period, unlike fixed-window counters that reset
 * on a clock boundary and allow bursts at the edges.
 */

const createRateLimiter = (options = {}) => {
  const windowMs = Number.isFinite(options.windowMs) && options.windowMs > 0
    ? options.windowMs
    : 60000;

  const maxRequests = Number.isFinite(options.maxRequests) && options.maxRequests > 0
    ? Math.floor(options.maxRequests)
    : 100;

  // In-memory store: IP -> sorted array of request timestamps (ms since epoch)
  // Only timestamps inside the current window are kept.
  const requests = new Map();

  // Periodic cleanup: every 60 seconds, drop IPs that have no recent activity.
  // This prevents unbounded memory growth for IPs that make a few requests
  // and then disappear.
  const CLEANUP_INTERVAL_MS = 60000;

  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    const cutoff = now - windowMs;

    for (const [ip, timestamps] of requests.entries()) {
      // Filter in place conceptually; only keep those >= cutoff
      // Because we always prune on access, this mostly catches long-idle IPs.
      let i = 0;
      while (i < timestamps.length && timestamps[i] < cutoff) {
        i++;
      }
      if (i === 0) {
        // nothing to prune, but guard against empty arrays lingering
        if (timestamps.length === 0) {
          requests.delete(ip);
        }
      } else if (i === timestamps.length) {
        requests.delete(ip);
      } else {
        requests.set(ip, timestamps.slice(i));
      }
    }
  }, CLEANUP_INTERVAL_MS);

  // Allow the interval to be garbage-collected if the process has no other work.
  // The caller must still call close() on graceful shutdown for full cleanup.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  /**
   * The actual middleware function.
   * Attaches a .close() method for stopping the cleanup timer.
   */
  const rateLimiter = (req, res, next) => {
    // ------------------------------------------------------------------
    // IMPORTANT: req.ip behavior behind proxies
    //
    // Express's `req.ip` (and `req.ips`) relies on the `X-Forwarded-For` header
    // (and similar) ONLY when the app has been told to trust the proxy chain:
    //
    //   app.set('trust proxy', true);          // trust first proxy
    //   // or
    //   app.set('trust proxy', 1);             // trust exactly 1 hop
    //   app.set('trust proxy', 'loopback');    // trust only loopback, etc.
    //
    // Without `trust proxy`, `req.ip` will usually be the IP of the *last*
    // proxy (or the load balancer / reverse proxy), not the real client.
    // In production behind Nginx, Cloudflare, ALB, etc. you *must* configure
    // trust proxy correctly, otherwise rate limiting will be applied per-proxy
    // IP instead of per-client, defeating the purpose (or rate-limiting
    // everyone behind the same proxy together).
    //
    // See: https://expressjs.com/en/guide/behind-proxies.html
    // ------------------------------------------------------------------
    const ip =
      (req.ip && req.ip !== '::1' && req.ip !== '127.0.0.1' ? req.ip : null) ||
      req.headers['x-forwarded-for']?.split(',')[0]?.trim() ||
      req.connection?.remoteAddress ||
      req.socket?.remoteAddress ||
      'unknown';

    const now = Date.now();
    const cutoff = now - windowMs;

    // Get (or create) the list for this IP and prune old entries.
    let timestamps = requests.get(ip) || [];

    // Remove timestamps older than the window (true sliding window semantics)
    // We keep the array sorted because we only append newer timestamps.
    let firstValidIndex = 0;
    while (firstValidIndex < timestamps.length && timestamps[firstValidIndex] < cutoff) {
      firstValidIndex++;
    }
    if (firstValidIndex > 0) {
      timestamps = timestamps.slice(firstValidIndex);
    }

    const currentCount = timestamps.length;

    // Headers we will always set (standard rate-limit headers)
    const limit = maxRequests;

    // Calculate a sensible X-RateLimit-Reset:
    // In a sliding window this is the time (epoch seconds) when the *oldest*
    // still-active request will fall out of the window, i.e. the moment one
    // additional request becomes allowed again.
    // If there are no requests yet, use a full window from now.
    let resetEpochSeconds;
    if (timestamps.length > 0) {
      const oldest = timestamps[0];
      resetEpochSeconds = Math.ceil((oldest + windowMs) / 1000);
    } else {
      resetEpochSeconds = Math.ceil((now + windowMs) / 1000);
    }

    if (currentCount >= maxRequests) {
      // Rate limit exceeded.
      // retryAfter = seconds until the oldest request expires from the window.
      const oldest = timestamps[0];
      const retryAfterMs = oldest + windowMs - now;
      const retryAfter = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.setHeader('X-RateLimit-Limit', limit);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', resetEpochSeconds);
      res.setHeader('Retry-After', retryAfter);

      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter
      });
    }

    // Request is allowed. Record the timestamp.
    timestamps.push(now);
    requests.set(ip, timestamps);

    const remaining = Math.max(0, limit - timestamps.length);

    // Update reset using the (still) oldest timestamp after append.
    // The oldest is now either the previous oldest or (if this is first) `now`.
    const newOldest = timestamps[0];
    const newReset = Math.ceil((newOldest + windowMs) / 1000);

    res.setHeader('X-RateLimit-Limit', limit);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', newReset);

    next();
  };

  /**
   * Stop the periodic cleanup timer.
   * Call this on server shutdown to allow the Node process to exit cleanly
   * and to avoid leaking the interval.
   */
  rateLimiter.close = () => {
    clearInterval(cleanupInterval);
  };

  // Also expose configuration for introspection / testing (optional but helpful)
  rateLimiter.windowMs = windowMs;
  rateLimiter.maxRequests = maxRequests;

  return rateLimiter;
};

module.exports = { createRateLimiter };

/**
 * USAGE EXAMPLE
 *
 * const express = require('express');
 * const { createRateLimiter } = require('./rate-limiter');
 *
 * const app = express();
 *
 * // 1. IMPORTANT: If running behind a reverse proxy (Nginx, Cloudflare, load balancer, etc.)
 * //    you MUST tell Express to trust the proxy so that req.ip reflects the real client IP
 * //    instead of the proxy IP. Without this, all clients behind the proxy share the same
 * //    rate limit bucket.
 * app.set('trust proxy', 1); // trust exactly one proxy hop (adjust for your infrastructure)
 *
 * // 2. Apply the rate limiter globally (or to specific routes/routers)
 * const limiter = createRateLimiter({
 *   windowMs: 60 * 1000,   // 1 minute sliding window
 *   maxRequests: 100       // max 100 requests per IP in any 60s period
 * });
 *
 * app.use(limiter);
 *
 * app.get('/api/resource', (req, res) => {
 *   res.json({ ok: true, ip: req.ip });
 * });
 *
 * // On server shutdown (e.g. SIGTERM handler) to allow clean process exit:
 * // process.on('SIGTERM', () => {
 * //   limiter.close();
 * //   server.close(() => process.exit(0));
 * // });
 *
 * // You can also apply it only to certain paths:
 * // app.use('/api/', createRateLimiter({ windowMs: 10000, maxRequests: 20 }));
 *
 * // Or mount per-router:
 * // const apiRouter = express.Router();
 * // apiRouter.use(createRateLimiter({ windowMs: 60000, maxRequests: 50 }));
 * // app.use('/api', apiRouter);
 */
```

